export interface LoginRequest {
  username: string;
  password: string;
}

export interface LoginResponse {
  token: string;
  expires_at: string; // ISO 8601
}

export type Role =
  | "Administrator"
  | "EventDirector"
  | "Referee"
  | "FinanceClerk"
  | "Auditor";

export interface AuthUser {
  user_id: number;
  username: string;
  roles: Role[];
  token: string;
}

// ── Assets ────────────────────────────────────────────────────────────────────
export type AssetCategory =
  | "vehicle"
  | "equipment"
  | "facility"
  | "electronic"
  | "other";

export type AssetStatus = "in_service" | "out_for_repair" | "retired";

export interface Asset {
  id: number;
  asset_code: string;
  category: AssetCategory;
  brand: string;
  model: string;
  status: AssetStatus;
  procurement_cost: string | null;
  procurement_date: string | null;
  useful_life_months: number | null;
  notes: string | null;
  created_at: string;
  updated_at: string;
}

export interface AssetListParams {
  category?: AssetCategory;
  status?: AssetStatus;
  page?: number;
  page_size?: number;
}

// ── Events ────────────────────────────────────────────────────────────────────
export type EventStatus =
  | "draft"
  | "published"
  | "in_progress"
  | "completed"
  | "cancelled";

export interface MotorsportEvent {
  id: number;
  name: string;
  description: string | null;
  venue_identifier: string | null;
  schedule_group: string | null;
  status: EventStatus;
  is_championship_class: boolean;
  created_at: string;
  updated_at: string;
}

// ── API Error ─────────────────────────────────────────────────────────────────
export interface ApiError {
  code: string;
  message: string;
  correlation_id?: string;
}

// ── Pagination ────────────────────────────────────────────────────────────────
export interface PaginatedResult<T> {
  data: T[];
  total: number;
  page: number;
  page_size: number;
}
"}

{"file_path": "/c/Users/user/Desktop/eaglepoint_new/Week-2/TASK-93/repo/frontend/src/utils/token.ts", "content": "const TOKEN_KEY = "ms_session_token";
const USER_KEY = "ms_session_user";

export function saveToken(token: string): void {
  sessionStorage.setItem(TOKEN_KEY, token);
}

export function getToken(): string | null {
  if (typeof window === "undefined") return null;
  return sessionStorage.getItem(TOKEN_KEY);
}

export function clearToken(): void {
  sessionStorage.removeItem(TOKEN_KEY);
  sessionStorage.removeItem(USER_KEY);
}

export function saveUser(user: object): void {
  sessionStorage.setItem(USER_KEY, JSON.stringify(user));
}

export function getUser<T>(): T | null {
  if (typeof window === "undefined") return null;
  const raw = sessionStorage.getItem(USER_KEY);
  if (!raw) return null;
  try {
    return JSON.parse(raw) as T;
  } catch {
    return null;
  }
}
"}

