{"file_path": "/c/Users/user/Desktop/eaglepoint_new/Week-2/TASK-93/repo/frontend/src/context/ToastContext.tsx", "content": "import React, {
  createContext,
  useCallback,
  useContext,
  useRef,
  useState,
} from "react";

export type ToastVariant = "success" | "error" | "info";

export interface Toast {
  id: string;
  message: string;
  variant: ToastVariant;
}

interface ToastCtx {
  toasts: Toast[];
  addToast: (message: string, variant?: ToastVariant) => void;
  removeToast: (id: string) => void;
}

const ToastContext = createContext<ToastCtx | null>(null);

export function ToastProvider({ children }: { children: React.ReactNode }) {
  const [toasts, setToasts] = useState<Toast[]>([]);
  const counter = useRef(0);

  const removeToast = useCallback((id: string) => {
    setToasts((prev) => prev.filter((t) => t.id !== id));
  }, []);

  const addToast = useCallback(
    (message: string, variant: ToastVariant = "info") => {
      const id = String(++counter.current);
      setToasts((prev) => [...prev, { id, message, variant }]);
      setTimeout(() => removeToast(id), 5000);
    },
    [removeToast]
  );

  return (
    <ToastContext.Provider value={{ toasts, addToast, removeToast }}>
      {children}
    </ToastContext.Provider>
  );
}

export function useToast(): ToastCtx {
  const ctx = useContext(ToastContext);
  if (!ctx) throw new Error("useToast must be used within ToastProvider");
  return ctx;
}
"}

{"file_path": "/c/Users/user/Desktop/eaglepoint_new/Week-2/TASK-93/repo/frontend/src/context/AuthContext.tsx", "content": "import React, { createContext, useCallback, useContext, useEffect, useState } from "react";
import { authService } from "@/services/auth.service";
import { clearToken, getToken, getUser, saveToken, saveUser } from "@/utils/token";
import type { AuthUser, LoginRequest, Role } from "@/types";

interface AuthCtx {
  user: AuthUser | null;
  isLoading: boolean;
  login: (creds: LoginRequest) => Promise<void>;
  logout: () => Promise<void>;
  hasRole: (role: Role) => boolean;
}

const AuthContext = createContext<AuthCtx | null>(null);

export function AuthProvider({ children }: { children: React.ReactNode }) {
  const [user, setUser] = useState<AuthUser | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  // Rehydrate from sessionStorage on mount
  useEffect(() => {
    const stored = getUser<AuthUser>();
    const token = getToken();
    if (stored && token) {
      setUser({ ...stored, token });
    }
    setIsLoading(false);
  }, []);

  const login = useCallback(async (creds: LoginRequest) => {
    const res = await authService.login(creds);
    // The API returns a token; we don't get roles from the login endpoint
    // so we infer them lazily. Roles are enforced server-side anyway.
    const authUser: AuthUser = {
      user_id: 0,
      username: creds.username,
      roles: [],
      token: res.token,
    };
    saveToken(res.token);
    saveUser(authUser);
    setUser(authUser);
  }, []);

  const logout = useCallback(async () => {
    try {
      await authService.logout();
    } finally {
      clearToken();
      setUser(null);
    }
  }, []);

  const hasRole = useCallback(
    (role: Role) => user?.roles.includes(role) ?? false,
    [user]
  );

  return (
    <AuthContext.Provider value={{ user, isLoading, login, logout, hasRole }}>
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth(): AuthCtx {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error("useAuth must be used within AuthProvider");
  return ctx;
}
"}

