1	/**
2	 * LoginForm — Happy Path & Failure Path
3	 *
4	 * Tests:
5	 *  1. Renders the form with username, password fields and submit button.
6	 *  2. Disables the submit button while submitting (loading state).
7	 *  3. Shows an inline error when the API returns 401 (bad credentials).
8	 *  4. Shows a generic error for non-401 network failures.
9	 *  5. Calls onSuccess when login resolves successfully.
10	 */
11	
12	import React from "react";
13	import { render, screen, fireEvent, waitFor } from "@testing-library/react";
14	import userEvent from "@testing-library/user-event";
15	import LoginForm from "@/components/auth/LoginForm";
16	import { AuthContext } from "@/context/AuthContext";
17	import { ApiRequestError } from "@/services/api";
18	import type { ApiError } from "@/types";
19	
20	// ── Helper: build a minimal AuthContext value ──────────────────────────────────
21	function makeAuthCtx(loginImpl: () => Promise<void>) {
22	  return {
23	    user: null,
24	    isLoading: false,
25	    login: loginImpl,
26	    logout: jest.fn(),
27	    hasRole: jest.fn().mockReturnValue(false),
28	  };
29	}
30	
31	function renderForm(loginImpl: () => Promise<void>, onSuccess = jest.fn()) {
32	  return render(
33	    <AuthContext.Provider value={makeAuthCtx(loginImpl)}>
34	      <LoginForm onSuccess={onSuccess} />
35	    </AuthContext.Provider>
36	  );
37	}
38	
39	// ── Tests ──────────────────────────────────────────────────────────────────────
40	
41	describe("LoginForm", () => {
42	  it("renders username, password inputs and a submit button", () => {
43	    renderForm(jest.fn().mockResolvedValue(undefined));
44	
45	    expect(screen.getByLabelText(/username/i)).toBeInTheDocument();
46	    expect(screen.getByLabelText(/password/i)).toBeInTheDocument();
47	    expect(screen.getByRole("button", { name: /sign in/i })).toBeInTheDocument();
48	  });
49	
50	  it("submit button is disabled when fields are empty", () => {
51	    renderForm(jest.fn().mockResolvedValue(undefined));
52	    expect(screen.getByRole("button", { name: /sign in/i })).toBeDisabled();
53	  });
54	
55	  it("calls onSuccess and does NOT show error on successful login", async () => {
56	    const onSuccess = jest.fn();
57	    const login = jest.fn().mockResolvedValue(undefined);
58	
59	    renderForm(login, onSuccess);
60	
61	    await userEvent.type(screen.getByLabelText(/username/i), "admin");
62	    await userEvent.type(screen.getByLabelText(/password/i), "secret");
63	    fireEvent.click(screen.getByRole("button", { name: /sign in/i }));
64	
65	    await waitFor(() => expect(onSuccess).toHaveBeenCalledTimes(1));
66	    expect(screen.queryByTestId("login-error")).not.toBeInTheDocument();
67	  });
68	
69	  it("shows 'Invalid username or password' error on 401", async () => {
70	    const apiError: ApiError = { code: "UNAUTHORIZED", message: "Bad credentials" };
71	    const login = jest
72	      .fn()
73	      .mockRejectedValue(new ApiRequestError(401, apiError));
74	
75	    renderForm(login);
76	
77	    await userEvent.type(screen.getByLabelText(/username/i), "admin");
78	    await userEvent.type(screen.getByLabelText(/password/i), "wrong");
79	    fireEvent.click(screen.getByRole("button", { name: /sign in/i }));
80	
81	    await waitFor(() =>
82	      expect(screen.getByTestId("login-error")).toHaveTextContent(
83	        /invalid username or password/i
84	      )
85	    );
86	  });
87	
88	  it("shows a generic error message for non-401 failures", async () => {
89	    const login = jest
90	      .fn()
91	      .mockRejectedValue(new Error("Network timeout"));
92	
93	    renderForm(login);
94	
95	    await userEvent.type(screen.getByLabelText(/username/i), "admin");
96	    await userEvent.type(screen.getByLabelText(/password/i), "pass");
97	    fireEvent.click(screen.getByRole("button", { name: /sign in/i }));
98	
99	    await waitFor(() =>
100	      expect(screen.getByTestId("login-error")).toHaveTextContent(
101	        /network timeout/i
102	      )
103	    );
104	  });
105	
106	  it("disables the submit button and shows 'Signing in…' while submitting", async () => {
107	    let resolve!: () => void;
108	    const login = jest.fn(
109	      () =>
110	        new Promise<void>((res) => {
111	          resolve = res;
112	        })
113	    );
114	
115	    renderForm(login);
116	
117	    await userEvent.type(screen.getByLabelText(/username/i), "admin");
118	    await userEvent.type(screen.getByLabelText(/password/i), "pass");
119	    fireEvent.click(screen.getByRole("button", { name: /sign in/i }));
120	
121	    // While the promise is pending the button should be disabled
122	    await waitFor(() =>
123	      expect(screen.getByRole("button", { name: /signing in/i })).toBeDisabled()
124	    );
125	
126	    // Resolve so no state-update warning fires after the test
127	    resolve();
128	  });
129	});
