1	import React, { createContext, useCallback, useContext, useEffect, useState } from "react";
2	import { authService } from "@/services/auth.service";
3	import { clearToken, getToken, getUser, saveToken, saveUser } from "@/utils/token";
4	import type { AuthUser, LoginRequest, Role } from "@/types";
5	
6	interface AuthCtx {
7	  user: AuthUser | null;
8	  isLoading: boolean;
9	  login: (creds: LoginRequest) => Promise<void>;
10	  logout: () => Promise<void>;
11	  hasRole: (role: Role) => boolean;
12	}
13	
14	export const AuthContext = createContext<AuthCtx | null>(null);
15	
16	export function AuthProvider({ children }: { children: React.ReactNode }) {
17	  const [user, setUser] = useState<AuthUser | null>(null);
18	  const [isLoading, setIsLoading] = useState(true);
19	
20	  // Rehydrate from sessionStorage on mount
21	  useEffect(() => {
22	    const stored = getUser<AuthUser>();
23	    const token = getToken();
24	    if (stored && token) {
25	      setUser({ ...stored, token });
26	    }
27	    setIsLoading(false);
28	  }, []);
29	
30	  const login = useCallback(async (creds: LoginRequest) => {
31	    const res = await authService.login(creds);
32	    // The API returns a token; we don't get roles from the login endpoint
33	    // so we infer them lazily. Roles are enforced server-side anyway.
34	    const authUser: AuthUser = {
35	      user_id: 0,
36	      username: creds.username,
37	      roles: [],
38	      token: res.token,
39	    };
40	    saveToken(res.token);
41	    saveUser(authUser);
42	    setUser(authUser);
43	  }, []);
44	
45	  const logout = useCallback(async () => {
46	    try {
47	      await authService.logout();
48	    } finally {
49	      clearToken();
50	      setUser(null);
51	    }
52	  }, []);
53	
54	  const hasRole = useCallback(
55	    (role: Role) => user?.roles.includes(role) ?? false,
56	    [user]
57	  );
58	
59	  return (
60	    <AuthContext.Provider value={{ user, isLoading, login, logout, hasRole }}>
61	      {children}
62	    </AuthContext.Provider>
63	  );
64	}
65	
66	export function useAuth(): AuthCtx {
67	  const ctx = useContext(AuthContext);
68	  if (!ctx) throw new Error("useAuth must be used within AuthProvider");
69	  return ctx;
70	}
