1	import { getToken } from "@/utils/token";
2	import type { ApiError } from "@/types";
3	
4	const BASE_URL =
5	  process.env.NEXT_PUBLIC_API_BASE_URL || "http://localhost:8000";
6	
7	export class ApiRequestError extends Error {
8	  public readonly status: number;
9	  public readonly code: string;
10	  public readonly correlationId?: string;
11	
12	  constructor(status: number, payload: ApiError) {
13	    super(payload.message);
14	    this.name = "ApiRequestError";
15	    this.status = status;
16	    this.code = payload.code;
17	    this.correlationId = payload.correlation_id;
18	  }
19	}
20	
21	async function request<T>(
22	  path: string,
23	  options: RequestInit = {}
24	): Promise<T> {
25	  const token = getToken();
26	
27	  const headers: HeadersInit = {
28	    "Content-Type": "application/json",
29	    ...(token ? { Authorization: `Bearer ${token}` } : {}),
30	    ...(options.headers ?? {}),
31	  };
32	
33	  const res = await fetch(`${BASE_URL}${path}`, { ...options, headers });
34	
35	  if (!res.ok) {
36	    let payload: ApiError;
37	    try {
38	      payload = (await res.json()) as ApiError;
39	    } catch {
40	      payload = { code: "UNKNOWN", message: `HTTP ${res.status}` };
41	    }
42	    throw new ApiRequestError(res.status, payload);
43	  }
44	
45	  // 204 No Content
46	  if (res.status === 204) return undefined as unknown as T;
47	
48	  return res.json() as Promise<T>;
49	}
50	
51	export const api = {
52	  get: <T>(path: string) => request<T>(path),
53	  post: <T>(path: string, body: unknown) =>
54	    request<T>(path, { method: "POST", body: JSON.stringify(body) }),
55	  put: <T>(path: string, body: unknown) =>
56	    request<T>(path, { method: "PUT", body: JSON.stringify(body) }),
57	  patch: <T>(path: string, body: unknown) =>
58	    request<T>(path, { method: "PATCH", body: JSON.stringify(body) }),
59	  del: <T>(path: string) => request<T>(path, { method: "DELETE" }),
60	};
61

