4	
5	const PAGE_SIZE = 10;
6	
7	interface UseAssetsReturn {
8	  assets: Asset[];
9	  filtered: Asset[];
10	  isLoading: boolean;
11	  error: string | null;
12	  search: string;
13	  setSearch: (v: string) => void;
14	  categoryFilter: AssetCategory | "";
15	  setCategoryFilter: (v: AssetCategory | "") => void;
16	  statusFilter: AssetStatus | "";
17	  setStatusFilter: (v: AssetStatus | "") => void;
18	  page: number;
19	  totalPages: number;
20	  setPage: (p: number) => void;
21	  reload: () => void;
22	}
23	
24	export function useAssets(): UseAssetsReturn {
25	  const [assets, setAssets] = useState<Asset[]>([]);
26	  const [isLoading, setIsLoading] = useState(false);
27	  const [error, setError] = useState<string | null>(null);
28	  const [search, setSearch] = useState("");
29	  const [categoryFilter, setCategoryFilter] = useState<AssetCategory | "">("");
30	  const [statusFilter, setStatusFilter] = useState<AssetStatus | "">("");
31	  const [page, setPage] = useState(1);
32	  const abortRef = useRef<AbortController | null>(null);
33	
34	  const load = useCallback(async () => {
35	    abortRef.current?.abort();
36	    abortRef.current = new AbortController();
37	
38	    setIsLoading(true);
39	    setError(null);
40	
41	    const params: AssetListParams = {};
42	    if (categoryFilter) params.category = categoryFilter;
43	    if (statusFilter) params.status = statusFilter;
44	
45	    try {
46	      const data = await assetsService.list(params);
47	      setAssets(data);
48	      setPage(1);
49	    } catch (err: unknown) {
50	      if (err instanceof Error && err.name !== "AbortError") {
51	        setError(err.message || "Failed to load assets.");
52	      }
53	    } finally {
54	      setIsLoading(false);
55	    }
56	  }, [categoryFilter, statusFilter]);
57	
58	  useEffect(() => {
59	    load();
60	  }, [load]);
61	
62	  const filtered = assets.filter((a) => {
63	    if (!search) return true;
64	    const q = search.toLowerCase();
65	    return (
66	      a.asset_code.toLowerCase().includes(q) ||
67	      a.brand.toLowerCase().includes(q) ||
68	      a.model.toLowerCase().includes(q)
69	    );
70	  });
71	
72	  const totalPages = Math.max(1, Math.ceil(filtered.length / PAGE_SIZE));
73	  const safePage = Math.min(page, totalPages);
74	
75	  return {
76	    assets,
77	    filtered: filtered.slice((safePage - 1) * PAGE_SIZE, safePage * PAGE_SIZE),
78	    isLoading,
79	    error,
80	    search,
81	    setSearch,
82	    categoryFilter,
83	    setCategoryFilter,
84	    statusFilter,
85	    setStatusFilter,
86	    page: safePage,
87	    totalPages,
88	    setPage,
89	    reload: load,
90	  };
91	}
