{"file_path": "/c/Users/user/Desktop/eaglepoint_new/Week-2/TASK-93/repo/frontend/src/pages/results.tsx", "content": "/**
 * Results page — lists all motorsport events with status, venue, and
 * championship-class indicator. Supports text search + status filtering
 * with client-side pagination.
 *
 * Interaction states covered:
 *   - loading  → <Spinner>
 *   - error    → <ErrorBanner> with Retry
 *   - empty    → <EmptyState>
 *   - data     → <EventsTable> with pagination
 */
import { useEffect } from "react";
import { useRouter } from "next/router";
import Head from "next/head";
import { useAuth } from "@/context/AuthContext";
import Layout from "@/components/layout/Layout";
import EventsSearch from "@/components/events/EventsSearch";
import EventsTable from "@/components/events/EventsTable";
import Spinner from "@/components/ui/Spinner";
import EmptyState from "@/components/ui/EmptyState";
import ErrorBanner from "@/components/ui/ErrorBanner";
import { useEvents } from "@/hooks/useEvents";
import styles from "./results.module.css";

export default function ResultsPage() {
  const { user, isLoading: authLoading } = useAuth();
  const router = useRouter();

  const {
    filtered,
    isLoading,
    error,
    search,
    setSearch,
    statusFilter,
    setStatusFilter,
    page,
    totalPages,
    setPage,
    reload,
  } = useEvents();

  useEffect(() => {
    if (!authLoading && !user) {
      router.replace("/login");
    }
  }, [user, authLoading, router]);

  if (authLoading) return <Spinner label="Loading…" />;
  if (!user) return null;

  return (
    <>
      <Head>
        <title>Results — Motorsport Ops</title>
      </Head>
      <Layout>
        <div className={styles.header}>
          <div>
            <h1 className={styles.heading}>Events &amp; Results</h1>
            <p className={styles.sub}>
              Browse all motorsport events. Click an event to view rankings and
              individual results.
            </p>
          </div>
        </div>

        <div className={styles.toolbar}>
          <EventsSearch
            search={search}
            onSearch={setSearch}
            status={statusFilter}
            onStatus={setStatusFilter}
          />
        </div>

        {error && (
          <div className={styles.errorWrapper}>
            <ErrorBanner message={error} onRetry={reload} />
          </div>
        )}

        {isLoading && <Spinner label="Loading events…" />}

        {!isLoading && !error && filtered.length === 0 && (
          <EmptyState
            title="No events found"
            message={
              search || statusFilter
                ? "Try clearing your search or status filter."
                : "No motorsport events have been created yet."
            }
          />
        )}

        {!isLoading && !error && filtered.length > 0 && (
          <EventsTable
            events={filtered}
            page={page}
            totalPages={totalPages}
            onPageChange={setPage}
          />
        )}
      </Layout>
    </>
  );
}
"}

