1	/**
2	 * LoginForm — Happy Path & Failure Path
3	 *
4	 * Tests:
5	 *  1. Renders the form with username, password fields and submit button.
6	 *  2. Disables the submit button while submitting (loading state).
7	 *  3. Shows an inline error when the API returns 401 (bad credentials).
8	 *  4. Shows a generic error for non-401 network failures.
9	 *  5. Calls onSuccess when login resolves successfully.
10	 */
11	
12	import React from "react";
13	import { render, screen, fireEvent, waitFor } from "@testing-library/react";
14	import userEvent from "@testing-library/user-event";
15	import LoginForm from "@/components/auth/LoginForm";
16	import { AuthContext } from "@/context/AuthContext";
17	import { ApiRequestError } from "@/services/api";
18	import type { ApiError, LoginRequest } from "@/types";
19	
20	// ── Helper: build a minimal AuthContext value ──────────────────────────────────
21	function makeAuthCtx(loginImpl: (creds: LoginRequest) => Promise<void>) {
22	  return {
23	    user: null,
24	    isLoading: false,
25	    login: loginImpl,
26	    logout: jest.fn<Promise<void>, []>().mockResolvedValue(undefined),
27	    hasRole: jest.fn().mockReturnValue(false),
28	  };
29	}
30	
31	function renderForm(
32	  loginImpl: (creds: LoginRequest) => Promise<void>,
33	  onSuccess = jest.fn()
34	) {
35	  return render(
36	    <AuthContext.Provider value={makeAuthCtx(loginImpl)}>
37	      <LoginForm onSuccess={onSuccess} />
38	    </AuthContext.Provider>
39	  );
40	}
41	
42	// ── Tests ──────────────────────────────────────────────────────────────────────
43	
44	describe("LoginForm", () => {
45	  it("renders username, password inputs and a submit button", () => {
46	    renderForm(jest.fn<Promise<void>, [LoginRequest]>().mockResolvedValue(undefined));
47	
48	    expect(screen.getByLabelText(/username/i)).toBeInTheDocument();
49	    expect(screen.getByLabelText(/password/i)).toBeInTheDocument();
50	    expect(screen.getByRole("button", { name: /sign in/i })).toBeInTheDocument();
51	  });
52	
53	  it("submit button is disabled when fields are empty", () => {
54	    renderForm(jest.fn<Promise<void>, [LoginRequest]>().mockResolvedValue(undefined));
55	    expect(screen.getByRole("button", { name: /sign in/i })).toBeDisabled();
56	  });
57	
58	  it("calls onSuccess and does NOT show error on successful login", async () => {
59	    const onSuccess = jest.fn();
60	    const login = jest.fn<Promise<void>, [LoginRequest]>().mockResolvedValue(undefined);
61	
62	    renderForm(login, onSuccess);
63	
64	    await userEvent.type(screen.getByLabelText(/username/i), "admin");
65	    await userEvent.type(screen.getByLabelText(/password/i), "secret");
66	    fireEvent.click(screen.getByRole("button", { name: /sign in/i }));
67	
68	    await waitFor(() => expect(onSuccess).toHaveBeenCalledTimes(1));
69	    expect(screen.queryByTestId("login-error")).not.toBeInTheDocument();
70	  });
71	
72	  it("shows 'Invalid username or password' error on 401", async () => {
73	    const apiError: ApiError = { code: "UNAUTHORIZED", message: "Bad credentials" };
74	    const login = jest
75	      .fn()
76	      .mockRejectedValue(new ApiRequestError(401, apiError));
77	
78	    renderForm(login);
79	
80	    await userEvent.type(screen.getByLabelText(/username/i), "admin");
81	    await userEvent.type(screen.getByLabelText(/password/i), "wrong");
82	    fireEvent.click(screen.getByRole("button", { name: /sign in/i }));
83	
84	    await waitFor(() =>
85	      expect(screen.getByTestId("login-error")).toHaveTextContent(
86	        /invalid username or password/i
87	      )
88	    );
89	  });
90	
91	  it("shows a generic error message for non-401 failures", async () => {
92	    const login = jest
93	      .fn()
94	      .mockRejectedValue(new Error("Network timeout"));
95	
96	    renderForm(login);
97	
98	    await userEvent.type(screen.getByLabelText(/username/i), "admin");
99	    await userEvent.type(screen.getByLabelText(/password/i), "pass");
100	    fireEvent.click(screen.getByRole("button", { name: /sign in/i }));
101	
102	    await waitFor(() =>
103	      expect(screen.getByTestId("login-error")).toHaveTextContent(
104	        /network timeout/i
105	      )
106	    );
107	  });
108	
109	  it("disables the submit button and shows 'Signing in…' while submitting", async () => {
110	    let resolve!: () => void;
111	    const login = jest.fn(
112	      () =>
113	        new Promise<void>((res) => {
114	          resolve = res;
115	        })
116	    );
117	
118	    renderForm(login);
119	
120	    await userEvent.type(screen.getByLabelText(/username/i), "admin");
121	    await userEvent.type(screen.getByLabelText(/password/i), "pass");
122	    fireEvent.click(screen.getByRole("button", { name: /sign in/i }));
