{"file_path": "/c/Users/user/Desktop/eaglepoint_new/Week-2/TASK-93/repo/frontend/src/components/invoices/InvoiceFormModal.tsx", "content": "import React, { useState } from "react";
import Modal from "@/components/ui/Modal";
import ErrorBanner from "@/components/ui/ErrorBanner";
import { invoicesService } from "@/services/invoices.service";
import { useToast } from "@/context/ToastContext";
import type { Invoice } from "@/types";
import styles from "./InvoiceFormModal.module.css";

interface InvoiceFormModalProps {
  isOpen: boolean;
  onClose: () => void;
  onCreated: (invoice: Invoice) => void;
}

export default function InvoiceFormModal({
  isOpen,
  onClose,
  onCreated,
}: InvoiceFormModalProps) {
  const { addToast } = useToast();
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const [counterparty, setCounterparty] = useState("");
  const [issueDate, setIssueDate] = useState(
    new Date().toISOString().slice(0, 10)   // default today
  );
  const [taxRate, setTaxRate] = useState("0.10");

  const isValid = counterparty.trim() !== "" && issueDate !== "";

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    if (!isValid) return;
    setError(null);
    setSubmitting(true);

    try {
      const created = await invoicesService.create({
        counterparty: counterparty.trim(),
        issue_date: issueDate,
        tax_rate: taxRate.trim() || undefined,
      });
      addToast(`Invoice ${created.invoice_no} created.`, "success");
      onCreated(created);
      onClose();
    } catch (err: unknown) {
      setError(
        err instanceof Error ? err.message : "Failed to create invoice."
      );
    } finally {
      setSubmitting(false);
    }
  }

  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      title="Create Invoice"
      size="sm"
    >
      <form onSubmit={handleSubmit} noValidate aria-label="Create invoice form">
        {error && (
          <div className={styles.errorWrap}>
            <ErrorBanner message={error} />
          </div>
        )}

        <div className={styles.field}>
