9	export type ToastVariant = "success" | "error" | "info";
10	
11	export interface Toast {
12	  id: string;
13	  message: string;
14	  variant: ToastVariant;
15	}
16	
17	interface ToastCtx {
18	  toasts: Toast[];
19	  addToast: (message: string, variant?: ToastVariant) => void;
20	  removeToast: (id: string) => void;
21	}
22	
23	const ToastContext = createContext<ToastCtx | null>(null);
24	
25	export function ToastProvider({ children }: { children: React.ReactNode }) {
26	  const [toasts, setToasts] = useState<Toast[]>([]);
27	  const counter = useRef(0);
28	
29	  const removeToast = useCallback((id: string) => {
30	    setToasts((prev) => prev.filter((t) => t.id !== id));
31	  }, []);
32	
33	  const addToast = useCallback(
34	    (message: string, variant: ToastVariant = "info") => {
35	      const id = String(++counter.current);
36	      setToasts((prev) => [...prev, { id, message, variant }]);
37	      setTimeout(() => removeToast(id), 5000);
38	    },
39	    [removeToast]
40	  );
41	
42	  return (
43	    <ToastContext.Provider value={{ toasts, addToast, removeToast }}>
44	      {children}
45	    </ToastContext.Provider>
46	  );
47	}
48	
49	export function useToast(): ToastCtx {
50	  const ctx = useContext(ToastContext);
51	  if (!ctx) throw new Error("useToast must be used within ToastProvider");
52	  return ctx;
53	}
